const headers = $input.first().json.headers || [];
const rows = $input.first().json.data || [];

// Mapeo básico de columnas comunes
const mapping = {
  'RFC': 'rfc',
  'rfc': 'rfc',
  'RFC ': 'rfc',
  'Nombre': 'nombre',
  'nombre': 'nombre',
  'Cliente': 'nombre',
  'Monto': 'monto',
  'monto': 'monto',
  'Importe': 'monto',
  'Cantidad': 'monto',
  'Concepto': 'concepto',
  'concepto': 'concepto',
  'Tipo': 'concepto',
  'Servicio': 'concepto',
  'Fecha': 'fechaVence',
  'fecha': 'fechaVence',
  'Vencimiento': 'fechaVence',
  'Telefono': 'telefono',
  'telefono': 'telefono',
  'Teléfono': 'telefono',
  'Email': 'email',
  'email': 'email',
  'Correo': 'email'
};

// Mapear filas al formato requerido
const mappedRows = rows.map(row => {
  const obj = {};
  row.forEach((value, index) => {
    const header = headers[index];
    const mappedField = mapping[header];
    if (mappedField && value !== undefined && value !== null && value !== '') {
      obj[mappedField] = value;
    }
  });
  // Convertir monto a número
  if (obj.monto) {
    obj.monto = typeof obj.monto === 'number' ? obj.monto : parseFloat(String(obj.monto).replace(/[$,]/g, '')) || 0;
  }
  return obj;
}).filter(r => r.rfc); // Solo filas con RFC

return { headers, rows: mappedRows };

// Generar mensaje WhatsApp personalizado
const client = $('Get Cliente por RFC').first().json;
const operations = $('Get Historial 3 meses').first().json || [];

const pendientes = operations.filter(o => !o.fechaPago);
const pagados = operations.filter(o => o.fechaPago);
const totalPendiente = pendientes.reduce((sum, p) => sum + p.monto, 0);
const totalPagado = pagados.reduce((sum, p) => sum + p.monto, 0);

const conceptosList = pendientes.map((p, i) => 
  `${i + 1}. ${p.descripcion || p.tipo}: $${Number(p.monto).toLocaleString('es-MX')}`
).join('\n');

const config = {
  nombre_despacho: 'Collecta',
  beneficiario: 'BajaTax Services',
  banco: 'BBVA',
  clabe: '012345678901234567',
  depto: 'Cobranzas',
  tel: '6641234567'
};

const mensaje = `*${config.nombre_despacho}* - Recordatorio de Pago\n\nEstimado *${client.nombre}*, le informamos que tiene los siguiente conceptos pendientes:\n\n${conceptosList}\n\n*TOTAL PENDIENTE: $${totalPendiente.toLocaleString('es-MX', {style: 'currency', currency: 'MXN'})}*\n\nPara realizar su pago:\n- Beneficiario: ${config.beneficiario}\n- Banco: ${config.banco}\n- CLABE: ${config.clabe}\n\nHistorial de pagos (3 meses): $${totalPagado.toLocaleString('es-MX')}\n\n${config.depto} | ${config.tel}`;

const telefono = client.telefono?.replace(/\D/g, '') || '';
const waUrl = telefono ? `https://wa.me/52${telefono}?text=${encodeURIComponent(mensaje)}` : null;

return {
  mensaje,
  waUrl,
  telefono,
  cliente: client.nombre,
  rfc: client.rfc,
  totalPendiente,
  totalPagado,
  pendientesCount: pendientes.length
};
